const leftToRight = keyframes`
    0% {
        transform: translateX(-100%);
        opacity: 0;
    }
    100% {
        transform: translateX(0);
        opacity: 1;
    }
`;

const rightToLeft = keyframes`
    0% {
        transform: translateX(100%);
        opacity: 0;
    }
    100% {
        transform: translateX(10%);
        opacity: 1;
    }
`;

const StyledComponent = styled.section`
    height: 100vh;
    position: fixed;
    background: ${DarkBlue};
    width: 100%;
    left: 0;
    top: 0;
    z-index: 9999999999999999999;
    display: flex;
    align-items: center;
    justify-content: center;

    .wrapper-text-motion {
        overflow: hidden;
        position: relative;
        display: flex;
        align-items: center;
        justify-content: center;
        flex-direction: column;

        svg {
            &:first-child {
                animation: ${leftToRight} 1.3s ease forwards;
                width: 100%;
                height: 70px;
            }

            &:last-child {
                animation: ${rightToLeft} 1.3s ease forwards;
                width: 100%;
                height: 15px;
                margin-top: 10px;
            }
        }
    }
`;

const MotionText = styled(motion.h1)`
    color: white;
    font-size: 2rem;
    text-align: center;
`;

export default PageTransition;
